<?= $this->extend('layouts/main') ?><?= $this->section('content') ?><!-- ══ Mobile: Scope Offcanvas ══ --><div class="offcanvas offcanvas-start" tabindex="-1" id="scopeOffcanvas" aria-labelledby="scopeOffcanvasLabel">    <div class="offcanvas-header">        <h6 class="offcanvas-title" id="scopeOffcanvasLabel">            <i class="bi bi-folder2"></i> <?= lang('App.search_scopes') ?>        </h6>        <button type="button" class="btn-close" data-bs-dismiss="offcanvas"></button>    </div>    <div class="offcanvas-body p-0">        <!-- reuse same sidebar content, populated by JS via syncOffcanvasSidebar() -->        <div id="scopeOffcanvasBody">            <div class="scope-sidebar-item scope-sidebar-all active" data-scope-ids="" id="ocAll">                <i class="bi bi-hdd-stack"></i>                <span><?= lang('App.local_search') ?></span>            </div>            <div class="scope-sidebar-item scope-sidebar-drive" data-scope-ids="__drive__" id="ocDrive">                <i class="bi bi-google" style="color:#4285F4"></i>                <span><?= lang('App.drive_search') ?></span>            </div>            <hr class="my-1">            <div id="ocScopeNodes"></div>        </div>    </div></div><!-- Search Top Bar --><div class="search-top-bar">    <form id="searchForm" onsubmit="return false;">        <!-- Search Input Row -->        <div class="d-flex gap-2 align-items-center">            <!-- Mobile: scope toggle button -->            <button type="button" class="btn btn-outline-secondary d-lg-none flex-shrink-0"                    data-bs-toggle="offcanvas" data-bs-target="#scopeOffcanvas" title="<?= lang('App.search_scopes') ?>">                <i class="bi bi-folder2"></i>            </button>            <div class="flex-grow-1 search-box">                <input type="text" id="searchInput" class="form-control"                       placeholder="<?= lang('App.search_placeholder') ?>"                       value="<?= esc($query ?? '') ?>" autocomplete="off">                        </div>            <button type="button" id="btnSearch" class="btn btn-primary">                <i class="bi bi-search"></i> <span class="d-none d-sm-inline"><?= lang('App.search') ?></span>            </button>            <button type="button" id="btnClear" class="btn btn-outline-secondary">                <i class="bi bi-x-lg"></i>            </button>        </div>        <!-- Filter Row (hidden — reserved for future use) -->        <div class="search-filters-row" id="filtersRow" style="display: none;">            <div>                <label class="form-label"><?= lang('App.court_level') ?></label>                <select id="filterCourt" class="form-select">                    <option value=""><?= lang('App.all') ?></option>                    <option value="first_instance"><?= lang('App.court_first_instance') ?></option>                    <option value="appeal"><?= lang('App.court_appeal') ?></option>                    <option value="tamyeez"><?= lang('App.court_tamyeez') ?></option>                    <option value="administrative"><?= lang('App.court_administrative') ?></option>                    <option value="constitutional"><?= lang('App.court_constitutional') ?></option>                    <option value="commercial"><?= lang('App.court_commercial') ?></option>                    <option value="criminal"><?= lang('App.court_criminal') ?></option>                    <option value="personal_status"><?= lang('App.court_personal_status') ?></option>                    <option value="labor"><?= lang('App.court_labor') ?></option>                </select>            </div>            <div>                <label class="form-label"><?= lang('App.date_from') ?></label>                <input type="date" id="filterDateFrom" class="form-control">            </div>            <div>                <label class="form-label"><?= lang('App.date_to') ?></label>                <input type="date" id="filterDateTo" class="form-control">            </div>            <div class="d-flex gap-3 align-items-center" style="padding-bottom: 2px;">                <div class="form-check">                    <input class="form-check-input" type="checkbox" id="chkFuzzy">                    <label class="form-check-label" for="chkFuzzy"><?= lang('App.fuzzy_search') ?></label>                </div>                <div class="form-check">                    <input class="form-check-input" type="checkbox" id="chkSynonyms">                    <label class="form-check-label" for="chkSynonyms"><?= lang('App.synonym_search') ?></label>                </div>            </div>        </div>    </form></div><!-- DocFetcher Split Layout: Scopes Sidebar + (Results + Preview) --><div class="search-outer-layout"><!-- ══ Mobile Tab Bar (visible only on small screens) ══ --><ul class="nav nav-tabs search-mobile-tabs d-lg-none mb-2" id="searchMobileTabs">    <li class="nav-item flex-fill text-center">        <button class="nav-link active w-100" id="mobileTabResults" type="button">            <i class="bi bi-list-ul"></i> <?= lang('App.search_results') ?>            <span class="badge bg-secondary ms-1" id="mobileResultsBadge" style="display:none;"></span>        </button>    </li></ul><!-- ══ SCOPES SIDEBAR ══ --><div class="search-scope-sidebar" id="searchScopeSidebar">    <div class="scope-sidebar-header">        <i class="bi bi-folder2"></i>        <span><?= lang('App.search_scopes') ?></span>    </div>    <div class="scope-sidebar-body">        <!-- Local tab -->        <div class="scope-sidebar-item scope-sidebar-all active" data-scope-ids="" id="ssAll">            <i class="bi bi-hdd-stack"></i>            <span><?= lang('App.local_search') ?></span>        </div>        <!-- Drive tab -->        <div class="scope-sidebar-item scope-sidebar-drive" data-scope-ids="__drive__" id="ssDrive">            <i class="bi bi-google" style="color:#4285F4"></i>            <span><?= lang('App.drive_search') ?></span>        </div>        <hr class="my-1">        <!-- Scope checkboxes tree -->        <div id="ssScopeNodes"><!-- populated by JS --></div>    </div></div><!-- ══ MAIN SEARCH AREA ══ --><div class="search-split-container" id="splitContainer">    <!-- ══ MAIN AREA ══ -->    <div class="search-main-area">        <!-- Second search bar: re-search within first results (always visible) -->        <div class="second-search-bar" id="secondSearchBar">            <button type="button" class="btn btn-sm btn-outline-secondary" id="btnInDocClear" title="<?= lang('App.clear') ?>">                <i class="bi bi-x-lg"></i>            </button>            <input type="text" id="inDocSearch" class="form-control form-control-sm"                   placeholder="<?= lang('App.search_within_results') ?>">            <button type="button" class="btn btn-sm btn-primary" id="btnInDocSearch" title="<?= lang('App.search_within_results') ?>">                <i class="bi bi-search"></i>            </button>        </div>        <!-- Mobile: toggle second search bar -->        <div class="d-lg-none px-2 pt-1 pb-0" id="mobileFilterToggleWrap" style="display:none!important;">            <button type="button" class="btn btn-sm btn-outline-secondary w-100" id="btnToggleSecondSearch">                <i class="bi bi-funnel"></i> <?= lang('App.search_within_results') ?>            </button>        </div>        <!-- Results Table (top) — Desktop -->        <div class="search-file-panel" id="filePanel" data-mobile-panel="results">            <div class="file-table-wrapper">                <table class="file-data-table">                    <thead>                        <tr>                            <th><?= lang('App.col_title') ?></th>                            <th><?= lang('App.col_score') ?></th>                            <th><?= lang('App.col_size') ?></th>                            <th><?= lang('App.col_file') ?></th>                            <th><?= lang('App.col_type') ?></th>                            <th><?= lang('App.col_date') ?></th>                        </tr>                    </thead>                    <tbody id="fileList">                        <!-- Populated by JS -->                    </tbody>                </table>            </div>                        <div class="file-panel-status" id="filePanelStatus">                <?= lang('App.search_results') ?>: 0            </div>        </div>        <!-- Split Handle (draggable) -->        <div class="split-handle" id="splitHandle"></div>        <!-- Preview Panel (bottom) -->        <div class="search-preview-panel" id="previewPanel" data-mobile-panel="preview">            <!-- Toolbar (hidden until a document is selected) — dark blue -->            <div class="preview-toolbar" id="previewToolbar" style="display: none;">                <span class="preview-doc-title" id="previewTitle"></span>                <div class="match-nav">                    <button class="btn btn-sm btn-nav" id="btnPrevMatch" title="<?= lang('App.prev_match') ?>">                        <i class="bi bi-chevron-left"></i>                    </button>                    <span class="match-counter" id="matchCounter">0 / 0</span>                    <button class="btn btn-sm btn-nav" id="btnNextMatch" title="<?= lang('App.next_match') ?>">                        <i class="bi bi-chevron-right"></i>                    </button>                </div>                <a href="#" class="btn btn-sm" id="btnDownloadDoc">                    <i class="bi bi-download"></i>                </a>                <a href="#" class="btn btn-sm" id="btnOpenDoc" target="_blank" title="فتح في نافذة جديدة">                    <i class="bi bi-box-arrow-up-right"></i>                </a>            </div>            <!-- Keyword navigation toolbar -->            <div class="keyword-nav-toolbar" id="keywordNavToolbar" style="display: none;">                <i class="bi bi-search keyword-nav-icon"></i>                <select class="form-select form-select-sm keyword-nav-select" id="keywordSelect">                    <option value=""><?= lang('App.all_keywords') ?></option>                </select>                <button type="button" class="btn btn-sm btn-keyword-nav" id="btnKeywordPrev" title="<?= lang('App.prev_match') ?>">                    <i class="bi bi-chevron-right"></i>                </button>                <button type="button" class="btn btn-sm btn-keyword-nav" id="btnKeywordNext" title="<?= lang('App.next_match') ?>">                    <i class="bi bi-chevron-left"></i>                </button>                <span class="keyword-nav-counter" id="keywordNavCounter">0 / 0</span>            </div>            <!-- Meta bar -->            <div class="preview-meta" id="previewMeta" style="display: none;">                <span id="metaFileName"></span>                <span id="metaWordCount"></span>                <span id="metaCharCount"></span>                <span id="metaMatchCount"></span>            </div>            <!-- Content or Empty State -->            <div class="preview-empty" id="previewEmpty">                <div>                    <i class="bi bi-file-earmark-text"></i>                    <p><?= lang('App.select_document') ?></p>                </div>            </div>            <div class="preview-content-wrapper" id="previewWrapper" style="display: none;">                <div class="preview-content" id="previewContent"></div>                <div class="preview-marker-bar" id="previewMarkerBar"></div>            </div>        </div>    </div></div><!-- /.search-split-container --></div><!-- /.search-outer-layout --><!-- Drive Results Panel (shown when Drive tab active) --><div id="driveResultsPanel" class="drive-results-panel" style="display:none;">    <div class="drive-results-header">        <i class="bi bi-google" style="color:#4285F4"></i>        <span><?= lang('App.drive_results') ?></span>        <small id="driveResultsCount" class="text-muted ms-2"></small>    </div>    <div id="driveResultsList" class="drive-results-list">        <div class="text-center text-muted py-4"><i class="bi bi-search"></i> <?= lang('App.search_results') ?>: 0</div>    </div></div><?= $this->endSection() ?><?= $this->section('scripts') ?><style>/* ── Outer layout: sidebar + search area ─ */.search-outer-layout {    display: flex;    gap: 0;    align-items: flex-start;    min-height: 0;}.search-scope-sidebar {    width: 200px;    min-width: 160px;    flex-shrink: 0;    border: 1px solid var(--bs-border-color);    border-radius: 8px;    margin-inline-end: 10px;    background: var(--bs-body-bg);    overflow: hidden;}.search-split-container { flex: 1; min-width: 0; }/* Sidebar header */.scope-sidebar-header {    display: flex;    align-items: center;    gap: 6px;    padding: 7px 10px;    font-size: 0.75rem;    font-weight: 700;    text-transform: uppercase;    letter-spacing: 0.05em;    color: var(--bs-secondary-color);    border-bottom: 1px solid var(--bs-border-color);}/* Sidebar items */.scope-sidebar-body { padding: 4px 0; }.scope-sidebar-item {    display: flex;    align-items: center;    gap: 7px;    padding: 5px 10px;    font-size: 0.82rem;    cursor: pointer;    border-radius: 0;    transition: background 0.12s;    user-select: none;}.scope-sidebar-item:hover { background: var(--bs-tertiary-bg); }.scope-sidebar-item.active {    background: var(--bs-primary-bg-subtle);    color: var(--bs-primary);    font-weight: 600;}/* Scope checkboxes */.ss-scope-node { padding: 0; }.ss-scope-row {    display: flex;    align-items: center;    gap: 6px;    padding: 3px 10px;    font-size: 0.82rem;    cursor: pointer;    user-select: none;}.ss-scope-row:hover { background: var(--bs-tertiary-bg); }.ss-scope-row label { cursor: pointer; flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }.ss-children { padding-inline-start: 12px; }/* Drive results panel */.drive-results-panel {    margin-top: 10px;    border: 1px solid var(--bs-border-color);    border-radius: 8px;    overflow: hidden;}.drive-results-header {    display: flex;    align-items: center;    gap: 8px;    padding: 8px 14px;    background: var(--bs-tertiary-bg);    border-bottom: 1px solid var(--bs-border-color);    font-weight: 600;    font-size: 0.875rem;}.drive-results-list { padding: 4px 0; }.drive-result-item {    display: flex;    align-items: center;    gap: 10px;    padding: 7px 14px;    font-size: 0.875rem;    border-bottom: 1px solid var(--bs-border-color-translucent);    transition: background 0.1s;}.drive-result-item:last-child { border-bottom: none; }.drive-result-item:hover { background: var(--bs-tertiary-bg); }.drive-result-item .drive-item-name { flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }/* ── Mobile Tab Bar ─ */.search-mobile-tabs .nav-link {    font-size: 0.85rem;    padding: 0.5rem 0.75rem;}/* On mobile: sidebar hidden, permanent split view */@media (max-width: 991.98px) {    .search-scope-sidebar { display: none !important; }    /* Hide tab bar — not needed in split view */    #searchMobileTabs { display: none !important; }    /* Remove vertical split handle on mobile */    .split-handle { display: none; }    /* Make the outer layout fill available viewport height */    .search-outer-layout {        display: flex;        flex-direction: column;        height: calc(100svh - 120px - env(safe-area-inset-bottom, 0px));        min-height: 400px;    }    .search-split-container {        flex: 1;        width: 100%;        display: flex;        flex-direction: column;        min-height: 0;        overflow: hidden;    }    .search-main-area {        flex: 1;        display: flex;        flex-direction: column;        min-height: 0;    }    /* Results panel: fixed ~35% of container */    .search-file-panel {        flex: 0 0 35% !important;        height: auto !important;        max-height: none !important;        min-height: 120px;        display: flex;        flex-direction: column;        overflow: hidden;        border-bottom: 2px solid var(--bs-border-color);    }    .search-file-panel .search-card-list {        flex: 1;        overflow-y: auto;        -webkit-overflow-scrolling: touch;    }    /* Preview panel: flex 1 = takes ALL remaining space */    .search-preview-panel {        flex: 1 !important;        height: auto !important;        min-height: 0 !important;        display: flex;        flex-direction: column;        overflow: hidden;    }    .search-preview-panel .preview-content-wrapper {        flex: 1;        min-height: 0;        overflow: hidden;    }    .search-preview-panel .preview-content {        flex: 1;        min-height: 0;        overflow-y: auto;        -webkit-overflow-scrolling: touch;    }    /* Second search bar wraps nicely */    .second-search-bar {        flex-wrap: wrap;    }    .second-search-bar .form-control {        max-width: 100%;    }    /* Hide footer on mobile — panels fill the screen */    footer { display: none !important; }    /* Remove bottom margin/padding from main container */    main.container-fluid { padding-bottom: 0 !important; margin-bottom: 0 !important; }    }</style><script>(function() {    'use strict';    var Q = window.Qanony;    
    var searchInput     = document.getElementById('searchInput');    var btnSearch       = document.getElementById('btnSearch');    var btnClear        = document.getElementById('btnClear');    var filterCourt     = document.getElementById('filterCourt');    var filterDateFrom  = document.getElementById('filterDateFrom');    var filterDateTo    = document.getElementById('filterDateTo');    var chkFuzzy        = document.getElementById('chkFuzzy');    var chkSynonyms     = document.getElementById('chkSynonyms');    var inDocSearch     = document.getElementById('inDocSearch');    var btnInDocSearch  = document.getElementById('btnInDocSearch');    var btnInDocClear   = document.getElementById('btnInDocClear');    var secondSearchBar = document.getElementById('secondSearchBar');    var fileList        = document.getElementById('fileList');    var filePanelStatus = document.getElementById('filePanelStatus');    var previewToolbar  = document.getElementById('previewToolbar');    var previewMeta     = document.getElementById('previewMeta');    var previewTitle    = document.getElementById('previewTitle');    var previewEmpty    = document.getElementById('previewEmpty');    var previewContent  = document.getElementById('previewContent');    var previewWrapper  = document.getElementById('previewWrapper');    var previewMarkerBar = document.getElementById('previewMarkerBar');    var keywordNavToolbar = document.getElementById('keywordNavToolbar');    var keywordSelect    = document.getElementById('keywordSelect');    var btnKeywordPrev   = document.getElementById('btnKeywordPrev');    var btnKeywordNext   = document.getElementById('btnKeywordNext');    
    if (window.innerWidth < 992) {        document.body.appendChild(previewMarkerBar);        previewMarkerBar.style.display = 'none';        
        [previewToolbar, keywordNavToolbar, previewMeta].forEach(function(el) {            if (!el) return;            
        });    }    
    function updateMobileFixedBars() {        if (window.innerWidth >= 992) return;        
        [previewToolbar, keywordNavToolbar, previewMeta].forEach(function(el) {            if (!el) return;            el.style.position = '';            el.style.top = '';            el.style.left = '';            el.style.right = '';            el.style.zIndex = '';            el.style.width = '';        });        previewContent.style.paddingTop = '';    }    var keywordNavCounter = document.getElementById('keywordNavCounter');    var matchCounter    = document.getElementById('matchCounter');    var btnPrevMatch    = document.getElementById('btnPrevMatch');    var btnNextMatch    = document.getElementById('btnNextMatch');    var btnDownloadDoc  = document.getElementById('btnDownloadDoc');    var btnOpenDoc      = document.getElementById('btnOpenDoc');    var metaFileName    = document.getElementById('metaFileName');    var metaWordCount   = document.getElementById('metaWordCount');    var metaCharCount   = document.getElementById('metaCharCount');    var metaMatchCount  = document.getElementById('metaMatchCount');    var splitHandle     = document.getElementById('splitHandle');    var filePanel       = document.getElementById('filePanel');    var previewPanel    = document.getElementById('previewPanel');    
    var allResults     = [];    var firstSearchResults = [];    var firstSearchIds = [];    var isSecondSearch = false;    var currentDocId   = null;    var currentQuery   = '';    var highlights     = [];    var currentMatchIdx = -1;    var searchTotal    = 0;    var searchPage     = 1;    var searchTotalPages = 0;    var loadedFullText = '';    var inDocQuery     = '';    var activeChipWord = null;    var highlightsByWord = {};    
    var selectedScopeIds = [];   
    var isDriveMode = false;     
    
    var HIGHLIGHT_COLORS = ['search-highlight-0', 'search-highlight-1', 'search-highlight-2'];    
    var LANG = {        results_count:    '<?= lang('App.results_count', ['{0}']) ?>',        search_results:   '<?= lang('App.search_results') ?>',        no_results:       '<?= lang('App.no_results') ?>',        loading:          '<?= lang('App.loading') ?>',        word_count:       '<?= lang('App.word_count') ?>',        char_count:       '<?= lang('App.char_count') ?>',        matches:          '<?= lang('App.matches') ?>',        no_matches:       '<?= lang('App.no_matches') ?>',        select_document:  '<?= lang('App.select_document') ?>',        found_results:    '<?= lang('App.found_results', ['{0}', '{1}', '{2}']) ?>',        all_keywords:     '<?= lang('App.all_keywords') ?>',        no_doc_loaded:    '<?= lang('App.no_doc_loaded') ?>',        search_within_results: '<?= lang('App.search_within_results') ?>',    };    
    
    
    function doSearch(page) {        var query = searchInput.value.trim();        if (!query) return;        currentQuery = query;        loadAllInProgress = false;        page = page || 1;        
        if (isDriveMode) {            driveSearch(query);            return;        }        var mode = 'fulltext';        if (chkFuzzy.checked && chkSynonyms.checked) {            mode = 'synonym';        } else if (chkFuzzy.checked) {            mode = 'fuzzy';        } else if (chkSynonyms.checked) {            mode = 'synonym';        }        var params = new URLSearchParams();        params.set('q', query);        params.set('mode', mode);        params.set('per_page', '50');        params.set('page', String(page));        if (page > 1 && searchTotal > 0) params.set('known_total', String(searchTotal));        if (filterCourt.value)    params.set('court_level', filterCourt.value);        if (filterDateFrom.value) params.set('date_from', filterDateFrom.value);        if (filterDateTo.value)   params.set('date_to', filterDateTo.value);        if (selectedScopeIds.length > 0) params.set('scope_ids', selectedScopeIds.join(','));        var url = Q.siteUrl + '/search/results?' + params.toString();        
        fileList.innerHTML = '<tr class="file-table-empty"><td colspan="6"><i class="bi bi-hourglass-split"></i> ' + LANG.loading + '</td></tr>';        filePanelStatus.textContent = LANG.loading;        
        showEmptyPreview();        Q.ajax(url).then(function(data) {            if (!data || !data.items) {                allResults = [];                firstSearchResults = [];                firstSearchIds = [];                isSecondSearch = false;                searchTotal = 0;                searchPage = 1;                searchTotalPages = 0;                renderFileTable([]);                updateStatusBar();                return;            }            allResults = data.items;            firstSearchResults = data.items.slice();  
            firstSearchIds = data.items.map(function(item) { return item.id; });            isSecondSearch = false;            searchTotal = data.total || 0;            searchPage = data.page || 1;            searchTotalPages = data.total_pages || 1;            renderFileTable(allResults);            updateStatusBar();            if (isMobile()) showMobileTab('results');            
        }).catch(function(err) {            console.error('Search error:', err);            fileList.innerHTML = '<tr class="file-table-empty"><td colspan="6"><i class="bi bi-exclamation-triangle text-danger"></i> Error</td></tr>';            filePanelStatus.textContent = LANG.search_results + ': 0';        });    }    
    function updateStatusBar() {        if (searchTotal === 0) {            filePanelStatus.innerHTML = LANG.search_results + ': 0';            return;        }        var txt = LANG.found_results.replace('{0}', searchTotal).replace('{1}', searchPage).replace('{2}', searchTotalPages);        var html = txt;        if (allResults.length < searchTotal) {            html += ' &mdash; <button class="btn btn-sm btn-link py-0 px-1 ms-1" id="btnLoadAll">إظهار الكل</button>';        }        filePanelStatus.innerHTML = html;        var btnLoadAll = document.getElementById('btnLoadAll');        if (btnLoadAll) {            btnLoadAll.addEventListener('click', function() {                loadAllResults();            });        }    }    
    var loadAllInProgress = false;    function loadAllResults() {        if (loadAllInProgress) return;        loadAllInProgress = true;        var btnLoadAll = document.getElementById('btnLoadAll');        if (btnLoadAll) {            btnLoadAll.disabled = true;            btnLoadAll.textContent = LANG.loading;        }        var query = currentQuery;        var mode = 'fulltext';        if (chkFuzzy.checked && chkSynonyms.checked) { mode = 'synonym'; }        else if (chkFuzzy.checked)    { mode = 'fuzzy'; }        else if (chkSynonyms.checked) { mode = 'synonym'; }        var totalToFetch = searchTotalPages;        var nextPage = searchPage + 1;        var fetched = 0;        var needed = totalToFetch - searchPage;        if (needed <= 0) { loadAllInProgress = false; return; }        function fetchPage(page) {            var params = new URLSearchParams();            params.set('q', query);            params.set('mode', mode);            params.set('per_page', '50');            params.set('page', String(page));            if (filterCourt.value)    params.set('court_level', filterCourt.value);            if (filterDateFrom.value) params.set('date_from', filterDateFrom.value);            if (filterDateTo.value)   params.set('date_to', filterDateTo.value);            if (selectedScopeIds.length > 0) params.set('scope_ids', selectedScopeIds.join(','));            Q.ajax(Q.siteUrl + '/search/results?' + params.toString()).then(function(data) {                if (data && data.items && data.items.length > 0) {                    appendResultsToTable(data.items);                    allResults = allResults.concat(data.items);                }                fetched++;                if (fetched < needed && page < totalToFetch) {                    fetchPage(page + 1);                } else {                    loadAllInProgress = false;                    updateStatusBar();                    
                    var tableWrapper = document.querySelector('.file-table-wrapper');                        if (tableWrapper) tableWrapper.scrollTop = tableWrapper.scrollHeight;                }            }).catch(function() {                fetched++;                if (fetched < needed) fetchPage(page + 1);                else { loadAllInProgress = false; updateStatusBar(); }            });        }        fetchPage(nextPage);    }    
    function appendResultsToTable(items) {        
        var html = '';        for (var i = 0; i < items.length; i++) {            var doc = items[i];            var sizeStr  = doc.file_size ? formatFileSize(parseInt(doc.file_size)) : '-';            var dateStr  = doc.document_date || '-';            var titleStr = escHtml(doc.title || doc.file_name || '-');            var fileStr  = doc.file_name ? escHtml(doc.file_name) : '-';            var typeStr  = doc.document_type ? escHtml(doc.document_type) : '-';            var scoreStr = doc.relevance_score ? parseFloat(doc.relevance_score).toFixed(1) : '-';            html += '<tr data-id="' + doc.id + '">';            html += '<td class="col-title" title="' + escAttr(doc.title || '') + '">' + titleStr + '</td>';            html += '<td class="col-size" style="max-width:45px;">' + escHtml(scoreStr) + '</td>';            html += '<td class="col-size">' + sizeStr + '</td>';            html += '<td class="col-file" title="' + escAttr(doc.file_name || '') + '"><a class="file-dl-link" href="' + Q.siteUrl + '/documents/' + doc.id + '/download" target="_blank" onclick="event.stopPropagation()">' + fileStr + '</a></td>';            html += '<td class="col-type">' + typeStr + '</td>';            html += '<td class="col-date">' + escHtml(dateStr) + '</td>';            html += '</tr>';        }        fileList.insertAdjacentHTML('beforeend', html);        
        var newRows = fileList.querySelectorAll('tr[data-id]:not([data-bound])');        for (var j = 0; j < newRows.length; j++) {            newRows[j].setAttribute('data-bound', '1');            newRows[j].addEventListener('click', function() {                selectDocument(parseInt(this.getAttribute('data-id')));            });        }    }    
