    function buildKeywordDropdown(words) {        if (!words || words.length === 0) {            keywordNavToolbar.style.display = 'none';            return;        }        keywordNavToolbar.style.display = 'flex';        updateMobileFixedBars();        var html = '<option value="">' + LANG.all_keywords + ' (' + highlights.length + ')</option>';        
