    function buildMarkerBar() {        previewMarkerBar.innerHTML = '';        if (highlights.length === 0) {            previewMarkerBar.style.display = 'none';            return;        }        requestAnimationFrame(function() {            var isMob = window.innerWidth < 992;            var scrollContainer = isMob ? previewPanel : previewContent;            var scrollH = scrollContainer.scrollHeight;            var barH    = isMob ? window.innerHeight : (previewMarkerBar.clientHeight || previewMarkerBar.getBoundingClientRect().height);            if (scrollH <= 0 || barH <= 0) { setTimeout(buildMarkerBar, 150); return; }            var scrollTop = scrollContainer.scrollTop;            var fragment  = document.createDocumentFragment();            for (var i = 0; i < highlights.length; i++) {                var el = highlights[i];                
