    var markerResizeTimer;    window.addEventListener('resize', function() {        clearTimeout(markerResizeTimer);        markerResizeTimer = setTimeout(buildMarkerBar, 200);    });    
    function showEmptyPreview() {        previewToolbar.style.display = 'none';        previewMeta.style.display = 'none';        keywordNavToolbar.style.display = 'none';        previewWrapper.style.display = 'none';        previewEmpty.style.display = 'flex';        previewEmpty.innerHTML = '<div><i class="bi bi-file-earmark-text"></i><p>' + LANG.select_document + '</p></div>';        previewMarkerBar.innerHTML = '';        previewMarkerBar.style.display = 'none';        
        if (window.innerWidth < 992) {            [previewToolbar, keywordNavToolbar, previewMeta].forEach(function(el) {                if (el) { el.style.position = ''; el.style.top = ''; el.style.left = ''; el.style.right = ''; el.style.width = ''; }            });            previewContent.style.paddingTop = '';        }        currentDocId = null;        loadedFullText = '';        highlights = [];        highlightsByWord = {};        currentMatchIdx = -1;        activeChipWord = null;    }    
    
    
    (function() {        var isDragging = false;        var mainArea = filePanel.parentElement;        splitHandle.addEventListener('mousedown', function(e) {            isDragging = true;            e.preventDefault();            document.body.style.cursor = 'ns-resize';            document.body.style.userSelect = 'none';        });        document.addEventListener('mousemove', function(e) {            if (!isDragging) return;            var rect = mainArea.getBoundingClientRect();            var offset = e.clientY - rect.top;            var totalH = rect.height;            var minH = 120;            if (offset < minH) offset = minH;            if (offset > totalH - minH) offset = totalH - minH;            filePanel.style.height = offset + 'px';            filePanel.style.maxHeight = 'none';        });        document.addEventListener('mouseup', function() {            if (isDragging) {                isDragging = false;                document.body.style.cursor = '';                document.body.style.userSelect = '';            }        });    })();    
    
    
