    document.addEventListener('keydown', function(e) {        if (e.key === 'F3' || (e.ctrlKey && e.key === 'g')) {            e.preventDefault();            var nav = getNavigableHighlights();            if (nav.length > 0) goToMatch(currentMatchIdx + 1);        }        if ((e.shiftKey && e.key === 'F3') || (e.ctrlKey && e.shiftKey && e.key === 'G')) {            e.preventDefault();            var navB = getNavigableHighlights();            if (navB.length > 0) goToMatch(currentMatchIdx - 1);        }    });    
    function escHtml(str) {        if (!str) return '';        var div = document.createElement('div');        div.textContent = str;        return div.innerHTML;    }    function escAttr(str) {        if (!str) return '';        return str.replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');    }    /**     * Parse a search query into terms, respecting quoted phrases.     * "حكم محكمة" قانون  =>  ["حكم محكمة", "قانون"]     * Supports straight quotes (") and curly quotes (\u201C, \u201D).     */    function parseSearchTerms(query) {        if (!query) return [];        var terms = [];        var len = query.length;        var i = 0;        while (i < len) {            var ch = query[i];            
            if (/\s/.test(ch)) { i++; continue; }            
            if (ch === '"' || ch === '\u201C' || ch === '\u201D') {                i++; 
                var phrase = '';                while (i < len) {                    var c = query[i];                    if (c === '"' || c === '\u201C' || c === '\u201D') { i++; break; }                    phrase += c;                    i++;                }                phrase = phrase.trim();                if (phrase.length > 0) terms.push(phrase);            } else {                
                var word = '';                while (i < len) {                    var c2 = query[i];                    if (/\s/.test(c2) || c2 === '"' || c2 === '\u201C' || c2 === '\u201D') break;                    word += c2;                    i++;                }                word = word.trim();                if (word.length > 0) terms.push(word);            }        }        return terms;    }    function formatFileSize(bytes) {        if (typeof Q.formatFileSize === 'function') return Q.formatFileSize(bytes);        if (!bytes || bytes === 0) return '0 B';        var k = 1024;        var sizes = ['B', 'KB', 'MB', 'GB'];        var i = Math.floor(Math.log(bytes) / Math.log(k));        return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];    }    
    
    
    function loadScopeSidebar() {        Q.ajax(Q.siteUrl + '/scopes/tree').then(function(data) {            if (!data || !data.tree) return;            var container = document.getElementById('ssScopeNodes');            container.innerHTML = renderSsScopeNodes(data.tree, 0);            bindSsScopeCheckboxes();        });    }    function renderSsScopeNodes(nodes, depth) {        if (!nodes || nodes.length === 0) return '';        var html = '';        nodes.forEach(function(node) {            var indent = depth * 12;            var hasChildren = node.children && node.children.length > 0;            html += '<div class="ss-scope-node" data-scope-id="' + node.id + '">';            html += '<div class="ss-scope-row" style="padding-inline-start:' + (10 + indent) + 'px">';            html += '<input type="checkbox" class="form-check-input ss-scope-cb" id="ss_scope_' + node.id + '" value="' + node.id + '">';            html += '<label for="ss_scope_' + node.id + '">';            html += '<i class="bi ' + (hasChildren ? 'bi-folder2' : 'bi-folder') + ' me-1"></i>';            html += escHtml(node.name);            html += ' <small class="text-muted">(' + (node.document_count || 0) + ')</small>';            html += '</label>';            html += '</div>';            if (hasChildren) {                html += '<div class="ss-children">' + renderSsScopeNodes(node.children, depth + 1) + '</div>';            }            html += '</div>';        });        return html;    }    function bindSsScopeCheckboxes() {        document.querySelectorAll('.ss-scope-cb').forEach(function(cb) {            cb.addEventListener('change', function() {                
                var node = this.closest('.ss-scope-node');                if (node) {                    var childCbs = node.querySelectorAll('.ss-scope-cb');                    childCbs.forEach(function(c) { c.checked = cb.checked; });                }                updateSelectedScopeIds();                
                doSearch();            });        });    }    function updateSelectedScopeIds() {        selectedScopeIds = [];        document.querySelectorAll('.ss-scope-cb:checked').forEach(function(cb) {            selectedScopeIds.push(parseInt(cb.value));        });    }    
    document.getElementById('ssAll').addEventListener('click', function() {        isDriveMode = false;        
        document.querySelectorAll('.ss-scope-cb').forEach(function(cb) { cb.checked = false; });        selectedScopeIds = [];        document.querySelectorAll('.scope-sidebar-item').forEach(function(el) { el.classList.remove('active'); });        this.classList.add('active');        document.getElementById('splitContainer').style.display = '';        document.getElementById('driveResultsPanel').style.display = 'none';    });    document.getElementById('ssDrive').addEventListener('click', function() {        isDriveMode = true;        document.querySelectorAll('.scope-sidebar-item').forEach(function(el) { el.classList.remove('active'); });        this.classList.add('active');        document.getElementById('splitContainer').style.display = 'none';        document.getElementById('driveResultsPanel').style.display = '';        var q = searchInput.value.trim();        if (q) driveSearch(q);    });    
    
    
    function driveSearch(query) {        var drivePanel = document.getElementById('driveResultsPanel');        var driveList  = document.getElementById('driveResultsList');        var driveCount = document.getElementById('driveResultsCount');        driveList.innerHTML = '<div class="text-center py-4"><div class="spinner-border spinner-border-sm text-primary"></div> <?= lang('App.loading') ?></div>';        drivePanel.style.display = '';        document.getElementById('splitContainer').style.display = 'none';        Q.ajax(Q.siteUrl + '/search/drive-results?q=' + encodeURIComponent(query)).then(function(data) {            if (data && data.not_configured) {                driveList.innerHTML = '<div class="text-center text-warning py-4"><i class="bi bi-exclamation-triangle"></i> <?= lang('App.drive_not_configured') ?></div>';                driveCount.textContent = '';                return;            }            if (!data || !data.items || data.items.length === 0) {                driveList.innerHTML = '<div class="text-center text-muted py-4"><i class="bi bi-search"></i> <?= lang('App.no_results') ?></div>';                driveCount.textContent = '(0)';                return;            }            driveCount.textContent = '(' + data.items.length + ')';            var html = '';            data.items.forEach(function(f) {                var ext = f.name ? f.name.split('.').pop().toLowerCase() : '';                var icon = ext === 'pdf' ? 'bi-file-pdf' : (ext === 'docx' || ext === 'doc') ? 'bi-file-word' : 'bi-file-earmark';                html += '<div class="drive-result-item">';                html += '<i class="bi ' + icon + ' text-secondary fs-5"></i>';                html += '<div class="drive-item-name" title="' + escAttr(f.name || '') + '">' + escHtml(f.name || '-') + '</div>';                html += '<small class="text-muted">' + formatFileSize(f.size || 0) + '</small>';                html += '<a href="' + escAttr(f.webViewLink || '#') + '" target="_blank" class="btn btn-sm btn-outline-primary ms-1" title="<?= lang('App.open_document') ?>"><i class="bi bi-box-arrow-up-right"></i></a>';                html += '</div>';            });            driveList.innerHTML = html;        }).catch(function() {            driveList.innerHTML = '<div class="text-center text-danger py-4"><i class="bi bi-exclamation-triangle"></i> Error</div>';        });    }    
    
    
    
<?php if (!empty($query)): ?>
    (function() {        searchInput.value = <?= json_encode($query) ?>;        <?php if (!empty($mode)): ?>        var mode = <?= json_encode($mode) ?>;        if (mode === 'fuzzy') chkFuzzy.checked = true;        if (mode === 'synonym') chkSynonyms.checked = true;        <?php endif; ?>        <?php if (!empty($filters['court_level'])): ?>        filterCourt.value = <?= json_encode($filters['court_level']) ?>;        <?php endif; ?>        <?php if (!empty($filters['date_from'])): ?>        filterDateFrom.value = <?= json_encode($filters['date_from']) ?>;        <?php endif; ?>        <?php if (!empty($filters['date_to'])): ?>        filterDateTo.value = <?= json_encode($filters['date_to']) ?>;        <?php endif; ?>        setTimeout(function() { doSearch(); }, 100);    })();    <?php endif; ?>    
