    var btnToggleSecondSearch = document.getElementById('btnToggleSecondSearch');    var mobileFilterWrap = document.getElementById('mobileFilterToggleWrap');    
    function showMobileFilterBtn() {        if (mobileFilterWrap && isMobile()) {            mobileFilterWrap.style.removeProperty('display');            mobileFilterWrap.style.display = '';            
            mobileFilterWrap.setAttribute('style', '');        }    }    if (btnToggleSecondSearch) {        btnToggleSecondSearch.addEventListener('click', function() {            var bar = document.getElementById('secondSearchBar');            if (bar.classList.contains('show-mobile')) {                bar.classList.remove('show-mobile');                this.innerHTML = '<i class="bi bi-funnel"></i> <?= lang('App.search_within_results') ?>';            } else {                bar.classList.add('show-mobile');                this.innerHTML = '<i class="bi bi-x-lg"></i> <?= lang('App.clear') ?>';                bar.querySelector('#inDocSearch').focus();            }        });    }    
    var _origUpdateStatusBar = updateStatusBar;    updateStatusBar = function() {        _origUpdateStatusBar.apply(this, arguments);        if (searchTotal > 0) showMobileFilterBtn();    };    
