    function updateMobileResultsBadge(count) {        if (mobileResultsBadge) {            if (count > 0) {                mobileResultsBadge.textContent = count;                mobileResultsBadge.style.display = '';            } else {                mobileResultsBadge.style.display = 'none';            }        }    }    
    var _origRenderResults = window._renderResults;    var statusObserver = new MutationObserver(function() {        var txt = filePanelStatus.textContent || '';        var m = txt.match(/\d+/);        if (m) updateMobileResultsBadge(parseInt(m[0]));    });    statusObserver.observe(filePanelStatus, { childList: true, subtree: true, characterData: true });    
    
